export const 止風符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.6) * k;
    const Z = (r) => (r - 5.0) * k + 1.0;
    const 線 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.65) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.42) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.2), Z(5.35)).L(X(7.0), Z(5.28)), 0.8);
    出(p => p.M(X(0.35), Z(5.40)).L(X(0.33), Z(16.30)).C(X(0.32), Z(16.84), X(0.22), Z(17.25), X(0.08), Z(17.52)), 0.7);
    出(p => p.M(X(6.8), Z(5.40)).L(X(6.78), Z(15.22)).C(X(6.8), Z(15.76), X(6.9), Z(16.16), X(7.05), Z(16.44)), 0.7);
    線(p => p.M(X(0.9), Z(6.20)).L(X(2.5), Z(6.16)), 0.55);
    線(p => p.M(X(0.9), Z(6.80)).L(X(2.5), Z(6.76)), 0.55);
    線(p => p.M(X(0.9), Z(7.40)).L(X(2.5), Z(7.36)), 0.55);
    線(p => p.M(X(4.2), Z(6.20)).C(X(5.00), Z(6.04), X(5.40), Z(6.12), X(5.8), Z(6.24)), 0.55);
    線(p => p.M(X(4.2), Z(6.80)).C(X(5.00), Z(6.64), X(5.40), Z(6.72), X(5.8), Z(6.84)), 0.55);
    線(p => p.M(X(4.2), Z(7.40)).C(X(5.00), Z(7.24), X(5.40), Z(7.32), X(5.8), Z(7.44)), 0.55);
    線(p => p.M(X(3.4), Z(5.45)).L(X(3.38), Z(8.00)), 0.6);
    // 未形
    線(p => p.M(X(1.0), Z(8.74)).L(X(3.2), Z(8.69)), 0.55);
    線(p => p.M(X(1.1), Z(9.82)).L(X(3.1), Z(9.77)), 0.55);
    線(p => p.M(X(2.1), Z(8.34)).L(X(2.08), Z(11.98)), 0.55);
    出(p => p.M(X(2.05), Z(9.96)).L(X(1.3), Z(11.44)), 0.5);
    出(p => p.M(X(2.15), Z(9.96)).L(X(2.9), Z(11.44)), 0.5);
    // 占形
    線(p => p.M(X(1.9), Z(12.52)).L(X(1.88), Z(13.87)), 0.55);
    線(p => p.M(X(1.9), Z(13.20)).L(X(2.7), Z(13.15)), 0.5);
    線(p => p.M(X(1.3), Z(14.01)).L(X(1.3), Z(15.49)).L(X(2.7), Z(15.44)).L(X(2.7), Z(13.95)).L(X(1.25), Z(14.01)), 0.5);
    // 右⺊心（點二）
    線(p => p.M(X(4.0), Z(12.25)).L(X(3.98), Z(13.60)), 0.55);
    線(p => p.M(X(4.0), Z(12.93)).L(X(4.7), Z(12.88)), 0.5);
    線(p => p.M(X(3.5), Z(14.41)).C(X(3.4), Z(15.36), X(3.8), Z(15.90), X(4.5), Z(15.90)).C(X(4.9), Z(15.90), X(5.1), Z(15.36), X(5.0), Z(14.95)), 0.55);
    點(4.2, 14.55, 0.14);
    點(4.75, 14.27, 0.14);
    // 币形
    出(p => p.M(X(2.4), Z(16.44)).L(X(1.5), Z(17.38)), 0.5);
    線(p => p.M(X(1.4), Z(17.65)).L(X(3.2), Z(17.58)), 0.55);
    線(p => p.M(X(1.7), Z(17.79)).L(X(1.68), Z(19.27)), 0.5);
    線(p => p.M(X(2.9), Z(17.72)).L(X(2.88), Z(19.20)), 0.5);
    線(p => p.M(X(2.3), Z(17.79)).L(X(2.28), Z(20.08)), 0.55);
    // 八形
    出(p => p.M(X(4.0), Z(17.11)).L(X(3.6), Z(18.59)), 0.55);
    出(p => p.M(X(4.4), Z(17.11)).L(X(4.9), Z(18.46)), 0.55);
    出(p => p.M(X(3.3), Z(20.48)).L(X(3.28), Z(22.51)), 0.62);
    點(3.3, 23.73);
};
